set-variable.value:
@{
        var jwt = (Jwt)context.Variables["validatedJwt"];
        var requiredScope = "__REQUIRED_SCOPE__";
        var requiredRole = "__REQUIRED_ROLE__";
        var vals = new System.Collections.Generic.List<string>();
        if (jwt.Claims.ContainsKey("scp")) {
            foreach (var s in jwt.Claims["scp"]) { foreach (var p in s.Split(' ')) { vals.Add(p); } }
        }
        if (jwt.Claims.ContainsKey("roles")) {
            foreach (var r in jwt.Claims["roles"]) { vals.Add(r); }
        }
        return vals.Contains(requiredScope) || vals.Contains(requiredRole);
    }

@{
          var body = (string)context.Variables.GetValueOrDefault("hrMcpRequestBody", string.Empty);
          if (string.IsNullOrWhiteSpace(body)) { return string.Empty; }
          try
          {
            var token = Newtonsoft.Json.Linq.JToken.Parse(body);
            if (token.Type == Newtonsoft.Json.Linq.JTokenType.Array) { return "__batch__"; }
            return token.SelectToken("method")?.ToString() ?? string.Empty;
          }
          catch { return string.Empty; }
        }

@{
              var jwt = (Jwt)context.Variables["validatedJwt"];
              var oid = jwt.Claims.ContainsKey("oid") ? jwt.Claims["oid"].FirstOrDefault() : "no-oid";
              var product = context.Product?.Id ?? "no-product";
              var subscription = context.Subscription?.Id ?? "no-subscription";
              return oid + "|" + product + "|" + subscription;
            }

trace.message:
@{
                var body = (string)context.Variables.GetValueOrDefault("hrMcpRequestBody", string.Empty);
                var snippet = body.Length > 2048 ? body.Substring(0, 2048) : body;
                var tool = string.Empty;
                try { tool = Newtonsoft.Json.Linq.JToken.Parse(body).SelectToken("params.name")?.ToString() ?? string.Empty; } catch { }
                return "HR MCP tools/call request; tool=" + tool + "; participantKey=" + (string)context.Variables["hrMcpRateLimitKey"] + "; bodySnippet=" + snippet;
              }

@{
            var body = (string)context.Variables.GetValueOrDefault("hrMcpResponseBody", string.Empty);
            var snippet = body.Length > 2048 ? body.Substring(0, 2048) : body;
            return "HR MCP tools/call response; status=" + context.Response.StatusCode + "; bodySnippet=" + snippet;
          }
